import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:vector_math/vector_math.dart';

/// Read-only snapshot of controller parameters for public exposure.
///
/// [FractalController] owns parameter validation and listener notification.
/// Returning the backing map lets callers mutate controller state without
/// normalization or notifications, so public reads get a defensive top-level
/// copy instead.
Map<String, Object> snapshotFractalControllerParams(
  Map<String, Object> params,
) {
  return Map<String, Object>.unmodifiable(params);
}

/// Defensive copy of controller view state for public exposure.
///
/// [FractalViewState] is immutable by field assignment, but its vector fields
/// are mutable. Clone vectors at the controller boundary so external reads
/// cannot mutate pan/rotation without going through controller update methods.
FractalViewState snapshotFractalControllerView(FractalViewState view) {
  return FractalViewState(
    pan: Vector2.copy(view.pan),
    zoom: view.zoom,
    rotation: Vector3.copy(view.rotation),
  );
}

import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:vector_math/vector_math.dart';

/// Pure bounds for gesture/view input accepted by FractalController.
///
/// Dart's [double.clamp] treats NaN as the upper bound. Gesture telemetry and
/// replayed state can occasionally contain NaN, and promoting that to max zoom
/// or max pan makes failures hard to replay. Preserve the last known-good value
/// for NaN while still clamping infinities to the explicit viewport limits.
/// Rotation has no explicit UI bounds, but shader uniforms still require finite
/// values; non-finite rotation components fall back to last known-good angles.
final class FractalViewInputBounds {
  static const double maxZoom = 1e12;
  static const double defaultMinZoom = 1e-9;
  static const double cantorSetMinZoom = 0.2;
  static const double minPan = -3.0;
  static const double maxPan = 3.0;

  const FractalViewInputBounds._();

  static double minZoomForModule(String moduleId) {
    switch (moduleId) {
      case 'cantor_set':
        // Prevent ultra-zoomed-out aliasing that appears as black vertical bands.
        return cantorSetMinZoom;
      default:
        return defaultMinZoom;
    }
  }

  static double normalizeZoom({
    required double candidate,
    required double currentZoom,
    required String moduleId,
  }) {
    final minZoom = minZoomForModule(moduleId);
    final fallback = currentZoom.isNaN ? minZoom : currentZoom;
    if (candidate.isNaN) return fallback.clamp(minZoom, maxZoom).toDouble();
    return candidate.clamp(minZoom, maxZoom).toDouble();
  }

  static double normalizePanComponent({
    required double candidate,
    required double current,
  }) {
    final fallback = current.isNaN ? 0.0 : current;
    if (candidate.isNaN) return fallback.clamp(minPan, maxPan).toDouble();
    return candidate.clamp(minPan, maxPan).toDouble();
  }

  static double normalizeRotationComponent({
    required double candidate,
    required double current,
  }) {
    if (candidate.isFinite) return candidate;
    return current.isFinite ? current : 0.0;
  }

  static Vector3 normalizeRotation({
    required Vector3 candidate,
    required Vector3 current,
  }) {
    return Vector3(
      normalizeRotationComponent(candidate: candidate.x, current: current.x),
      normalizeRotationComponent(candidate: candidate.y, current: current.y),
      normalizeRotationComponent(candidate: candidate.z, current: current.z),
    );
  }

  /// Sanitizes externally supplied view snapshots before they become controller
  /// state. Finite values preserve existing behavior; NaN values fall back to
  /// the last known-good view while infinities clamp to explicit bounds or, for
  /// unbounded rotation, fall back to the last known-good finite angle.
  static FractalViewState normalizeView({
    required FractalViewState candidate,
    required FractalViewState current,
    required String moduleId,
  }) {
    return candidate.copyWith(
      pan: Vector2(
        normalizePanComponent(
            candidate: candidate.pan.x, current: current.pan.x),
        normalizePanComponent(
            candidate: candidate.pan.y, current: current.pan.y),
      ),
      zoom: normalizeZoom(
        candidate: candidate.zoom,
        currentZoom: current.zoom,
        moduleId: moduleId,
      ),
      rotation: normalizeRotation(
        candidate: candidate.rotation,
        current: current.rotation,
      ),
    );
  }
}

import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  TestWidgetsFlutterBinding.ensureInitialized();

  group('FractalController', () {
    test('updateZoom clamps to [1e-9, 1e12]', () {
      final controller = FractalController(ModuleRegistry());

      controller.updateZoom(-1.0);
      expect(controller.view.zoom, 1e-9);

      controller.updateZoom(1e20);
      expect(controller.view.zoom, 1e12);

      controller.updateZoom(1.25);
      expect(controller.view.zoom, 1.25);
    });

    test('randomizeParams keeps values within schema bounds/options', () {
      final controller = FractalController(ModuleRegistry());
      // default module is registry.modules.first == mandelbrot.
      controller.randomizeParams();

      final iterations = controller.params['iterations'];
      final bailout = controller.params['bailout'];
      final colorScheme = controller.params['colorScheme'];
      final iterationsParam =
          controller.module.parameters.firstWhere((p) => p.id == 'iterations');

      expect(iterations, isA<int>());
      expect(
        iterations as int,
        inInclusiveRange(
          iterationsParam.min.round(),
          iterationsParam.max.round(),
        ),
      );

      expect(bailout, isA<double>());
      expect(bailout as double, inInclusiveRange(2.0, 50.0));
      // Mandelbrot bailout step is 0.1; randomize snaps to step.
      final snapped = ((bailout * 10).round() / 10);
      expect(bailout, closeTo(snapped, 1e-9));

      expect(colorScheme, isA<int>());
      expect(colorScheme as int, inInclusiveRange(0, 63));
    });

    test('updateZoom adaptively increases iterations when zooming in', () {
      final controller = FractalController(ModuleRegistry());
      final startZoom = controller.view.zoom;
      final startIterations = controller.params['iterations'] as int;
      final iterationsParam =
          controller.module.parameters.firstWhere((p) => p.id == 'iterations');

      controller.updateZoom(startZoom * 2.0);
      final afterZoom2 = controller.params['iterations'] as int;

      controller.updateZoom(startZoom * 32.0);
      final afterZoom32 = controller.params['iterations'] as int;

      controller.updateZoom(startZoom);
      final afterZoomOut = controller.params['iterations'] as int;

      expect(afterZoom2, greaterThan(startIterations));
      expect(afterZoom32, greaterThan(afterZoom2));
      expect(
        afterZoom32,
        inInclusiveRange(
          iterationsParam.min.round(),
          iterationsParam.max.round(),
        ),
      );
      // Adaptive policy only raises while zooming in; zooming out keeps budget.
      expect(afterZoomOut, afterZoom32);
    });
  });
}

import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart';

void main() {
  TestWidgetsFlutterBinding.ensureInitialized();

  test('FractalController.resetParams preserves view while restoring defaults',
      () {
    final controller = FractalController(ModuleRegistry());
    final initialIterations = controller.params['iterations'];

    controller.updateParam('iterations', 500);
    controller.updateZoom(2.5);
    controller.updatePan(Vector2(1.0, -2.0));
    controller.updateRotation(Vector3(0.1, 0.2, 0.3));

    final viewBeforeReset = controller.view;

    controller.resetParams();

    expect(controller.params['iterations'], initialIterations);
    expect(controller.view.zoom, viewBeforeReset.zoom);
    expect(controller.view.pan, viewBeforeReset.pan);
    expect(controller.view.rotation, viewBeforeReset.rotation);
  });

  test('FractalController.resetSession resets params + view + transparency', () {
    final controller = FractalController(ModuleRegistry());
    final initialIterations = controller.params['iterations'];

    // Mutate away from defaults.
    controller.updateParam('iterations', 500);
    controller.updateZoom(2.5);
    controller.updatePan(Vector2(1.0, -2.0));
    controller.setTransparentBackground(true);

    expect(controller.params['iterations'], 500);
    expect(controller.view.zoom, 2.5);
    expect(controller.transparentBackground, isTrue);

    controller.resetSession();

    // Defaults for the initial module (mandelbrot).
    expect(controller.params['iterations'], initialIterations);
    expect(controller.view.zoom, 1.0);
    expect(controller.view.pan, Vector2.zero());
    expect(controller.transparentBackground, isFalse);
  });
}

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/builders/escape_time/catalog.dart';
import 'package:flutter_fractals/core/modules/builders/raymarched_3d/catalog.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/catalog/catalog_entry.dart';

/// Catalog data source for the Explore screen.
///
/// Phase 1: derives entries from currently implemented modules while assigning
/// stable catalog IDs. This keeps IDs future-proof for PRD-200 ingest.
class CatalogRepository {
  final List<CatalogEntry> entries;

  const CatalogRepository({required this.entries});

  factory CatalogRepository.fromRegistry(ModuleRegistry registry) {
    final categoriesById = {
      for (final config in escapeTimeCatalog) config.id: config.category,
      for (final config in raymarched3DCatalog) config.id: config.category,
    };

    return CatalogRepository(
      entries: registry.modules
          .map(
            (module) => CatalogEntry(
              // Stable prefix to decouple future module refactors from IDs.
              catalogId: 'core.${module.id}',
              module: module,
              category: categoriesById[module.id] ??
                  (module.dimension == FractalDimension.threeD
                      ? '3D Fractals'
                      : 'Other'),
            ),
          )
          .toList(growable: false),
    );
  }

  CatalogEntry byCatalogId(String catalogId) {
    return entries.firstWhere((entry) => entry.catalogId == catalogId);
  }

  @visibleForTesting
  Set<String> allIds() => entries.map((e) => e.catalogId).toSet();
}

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';

/// Stable catalog entry used by the redesigned browser.
///
/// This is intentionally separate from [FractalModule] so we can scale the
/// catalog to many entries (e.g. PRD 200) while still mapping to currently
/// implemented render modules.
@immutable
class CatalogEntry {
  /// Stable ID for catalog persistence, analytics, and deep links.
  ///
  /// Must never change once published.
  final String catalogId;

  /// Backing runtime fractal module that can render this entry today.
  final FractalModule module;

  /// Display category used to group entries in the catalog UI.
  final String category;

  /// Optional search aliases used by catalog filtering.
  final List<String> aliases;

  const CatalogEntry({
    required this.catalogId,
    required this.module,
    required this.category,
    this.aliases = const [],
  });
}

import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/features/catalog/catalog_repository.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('CatalogRepository', () {
    test('creates stable prefixed IDs from module registry', () {
      final registry = ModuleRegistry();
      final repo = CatalogRepository.fromRegistry(registry);

      expect(repo.entries, isNotEmpty);
      expect(repo.entries.length, registry.modules.length);
      expect(repo.entries.first.catalogId, startsWith('core.'));
      expect(repo.byCatalogId('core.mandelbrot').module.id, 'mandelbrot');
    });

    test('catalog IDs are unique', () {
      final registry = ModuleRegistry();
      final repo = CatalogRepository.fromRegistry(registry);

      expect(repo.allIds().length, repo.entries.length);
    });

    test('keeps intended 3D runtime modules for implemented 3D catalog ids', () {
      final registry = ModuleRegistry();
      final repo = CatalogRepository.fromRegistry(registry);

      expect(
        repo.byCatalogId('core.quaternion_julia_3d').module.dimension,
        FractalDimension.threeD,
      );
      expect(
        repo.byCatalogId('core.dual_quaternion_julia').module.dimension,
        FractalDimension.threeD,
      );
      expect(
        repo.byCatalogId('core.mandelbox_shape_inversion').module.dimension,
        FractalDimension.threeD,
      );
    });
  });
}

